import React, { useEffect, useState } from 'react';
import ChatView from './views/ChatView';

const API_BASE_URL = process.env.REACT_APP_BACKEND_URL || 'http://localhost:8081';

function App() {
  const [userName, setUserName] = useState('');
  const [draftUserName, setDraftUserName] = useState('');
  const [rooms, setRooms] = useState([]);
  const [selectedRoomId, setSelectedRoomId] = useState('');
  const [joinSecret, setJoinSecret] = useState('');
  const [newRoomName, setNewRoomName] = useState('');
  const [newRoomSecret, setNewRoomSecret] = useState('');
  const [joinedRoom, setJoinedRoom] = useState(null);
  const [roomSecret, setRoomSecret] = useState('');
  const [error, setError] = useState('');
  const [isBusy, setIsBusy] = useState(false);

  const loadRooms = async () => {
    const response = await fetch(`${API_BASE_URL}/api/rooms`);
    const data = await response.json();

    if (!response.ok) {
      throw new Error(data.error || 'Failed to load rooms');
    }

    setRooms(data);
  };

  useEffect(() => {
    loadRooms().catch((loadError) => {
      setError(loadError.message);
    });
  }, []);

  const handleSetUserName = (event) => {
    event.preventDefault();
    const trimmedName = draftUserName.trim();

    if (!trimmedName) {
      setError('User name is required');
      return;
    }

    setUserName(trimmedName);
    setError('');
  };

  const handleCreateRoom = async (event) => {
    event.preventDefault();
    setIsBusy(true);
    setError('');

    try {
      const response = await fetch(`${API_BASE_URL}/api/rooms`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          name: newRoomName.trim(),
          password: newRoomSecret.trim(),
        }),
      });
      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.error || 'Failed to create room');
      }

      setNewRoomName('');
      setNewRoomSecret('');
      setSelectedRoomId(data.id);
      setRooms((currentRooms) => [...currentRooms, data]);
    } catch (createError) {
      setError(createError.message);
    } finally {
      setIsBusy(false);
    }
  };

  const handleJoinRoom = async (event) => {
    event.preventDefault();

    if (!selectedRoomId) {
      setError('Select a room first');
      return;
    }

    setIsBusy(true);
    setError('');

    try {
      const response = await fetch(`${API_BASE_URL}/api/rooms/${selectedRoomId}/join`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ secret: joinSecret.trim() }),
      });
      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.error || 'Failed to join room');
      }

      setJoinedRoom(data);
      setRoomSecret(joinSecret.trim());
      setJoinSecret('');
    } catch (joinError) {
      setError(joinError.message);
    } finally {
      setIsBusy(false);
    }
  };

  const handleLeaveRoom = () => {
    setJoinedRoom(null);
    setRoomSecret('');
    setError('');
  };

  if (joinedRoom) {
    return (
      <div className="app-shell">
        <ChatView
          apiBaseUrl={API_BASE_URL}
          room={joinedRoom}
          secret={roomSecret}
          userName={userName}
          onLeave={handleLeaveRoom}
        />
      </div>
    );
  }

  return (
    <div className="app-shell">
      <div className="lobby-card">
        <h1>Anonymous Chat</h1>
        <p className="subtitle">Choose a room, enter the secret, and chat only with members of that room.</p>
        {error ? <div className="error-banner">{error}</div> : null}

        {!userName ? (
          <form className="panel" onSubmit={handleSetUserName}>
            <h2>Your Name</h2>
            <input
              value={draftUserName}
              onChange={(event) => setDraftUserName(event.target.value)}
              placeholder="Enter your name"
            />
            <button type="submit">Continue</button>
          </form>
        ) : (
          <>
            <div className="panel panel-inline">
              <div>
                <strong>User:</strong> {userName}
              </div>
              <button type="button" onClick={() => setUserName('')}>Change name</button>
            </div>

            <form className="panel" onSubmit={handleCreateRoom}>
              <h2>Create Room</h2>
              <input
                value={newRoomName}
                onChange={(event) => setNewRoomName(event.target.value)}
                placeholder="Room name"
                disabled={isBusy}
              />
              <input
                value={newRoomSecret}
                onChange={(event) => setNewRoomSecret(event.target.value)}
                placeholder="Secret"
                type="password"
                disabled={isBusy}
              />
              <button type="submit" disabled={isBusy}>Create room</button>
            </form>

            <form className="panel" onSubmit={handleJoinRoom}>
              <div className="panel-header">
                <h2>Join Room</h2>
                <button type="button" onClick={() => loadRooms().catch((loadError) => setError(loadError.message))}>
                  Refresh rooms
                </button>
              </div>
              <div className="room-list">
                {rooms.map((room) => (
                  <label className={`room-option${selectedRoomId === room.id ? ' room-option-selected' : ''}`} key={room.id}>
                    <input
                      type="radio"
                      name="room"
                      value={room.id}
                      checked={selectedRoomId === room.id}
                      onChange={(event) => setSelectedRoomId(event.target.value)}
                    />
                    <span>{room.name}</span>
                    <code>{room.id}</code>
                  </label>
                ))}
                {rooms.length === 0 ? <div className="empty-state">No rooms yet.</div> : null}
              </div>
              <input
                value={joinSecret}
                onChange={(event) => setJoinSecret(event.target.value)}
                placeholder="Enter room secret"
                type="password"
                disabled={isBusy}
              />
              <button type="submit" disabled={isBusy}>Join room</button>
            </form>
          </>
        )}
      </div>
    </div>
  );
}

export default App;
